/**
 * Notification log model — tracks sent notifications for audit and history queries.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

export type DeliveryStatus = 'sent' | 'delivered' | 'failed';

export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  body: string;
  status: DeliveryStatus;
  error?: string;
  sentAt: Date;
  metadata?: Record<string, unknown>;
}

export interface NotificationHistoryQuery {
  recipient?: string;
  type?: NotificationType;
  channel?: NotificationChannel;
  status?: DeliveryStatus;
  fromDate?: Date;
  toDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type {
  NotificationLog,
  DeliveryStatus,
  NotificationHistoryQuery,
} from '../models/notification-log.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      subject: record['subject'] as string,
      body: record['body'] as string,
      status: record['status'] as DeliveryStatus,
      error: record['error'] as string | undefined,
      sentAt: new Date(record['sentAt'] as string),
      metadata: record['metadata']
        ? JSON.parse(record['metadata'] as string) as Record<string, unknown>
        : undefined,
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      subject: entity.subject,
      body: entity.body,
      status: entity.status,
      error: entity.error,
      sentAt: entity.sentAt.toISOString(),
      metadata: entity.metadata ? JSON.stringify(entity.metadata) : undefined,
    };
  }

  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  findByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.findAll((log) => log.status === status);
  }

  query(query: NotificationHistoryQuery): NotificationLog[] {
    return this.findAll((log) => {
      if (query.recipient && log.recipient !== query.recipient) return false;
      if (query.type && log.type !== query.type) return false;
      if (query.channel && log.channel !== query.channel) return false;
      if (query.status && log.status !== query.status) return false;
      if (query.fromDate && log.sentAt < query.fromDate) return false;
      if (query.toDate && log.sentAt > query.toDate) return false;
      return true;
    });
  }
}

/**
 * Notification history service — logs every sent notification and provides
 * query capabilities over the history.
 *
 * Integrates with NotificationService by wrapping the adapter dispatch:
 * after a notification is sent, the result (success or failure) is recorded
 * as a NotificationLog entry in the repository.
 */

import type { Notification, NotificationResult } from '../models/notification.js';
import type {
  NotificationLog,
  NotificationHistoryQuery,
  DeliveryStatus,
} from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Record a sent notification with its delivery result.
   */
  record(notification: Notification, result?: NotificationResult): NotificationLog {
    let status: DeliveryStatus;
    if (!result) {
      status = 'sent';
    } else if (result.success) {
      status = 'delivered';
    } else {
      status = 'failed';
    }

    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: notification.id,
      recipient: notification.recipient,
      channel: notification.channel,
      type: notification.type,
      subject: notification.subject,
      body: notification.body,
      status,
      error: result && !result.success ? result.error : undefined,
      sentAt: notification.sentAt,
      metadata: notification.metadata,
    };

    this.repository.save(log);
    this.logger.info(
      `Logged notification ${notification.id} — status: ${status}`,
    );

    return log;
  }

  /**
   * Update the delivery status of an existing log entry.
   */
  updateStatus(logId: string, status: DeliveryStatus, error?: string): NotificationLog {
    return this.repository.update(logId, { status, error });
  }

  /**
   * Query notification history with flexible filters.
   */
  query(query: NotificationHistoryQuery): NotificationLog[] {
    return this.repository.query(query);
  }

  /**
   * Get all logs for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all logs for a specific notification type.
   */
  getByType(type: NotificationLog['type']): NotificationLog[] {
    return this.repository.findByType(type);
  }

  /**
   * Get all logs within a date range.
   */
  getByDateRange(from: Date, to: Date): NotificationLog[] {
    return this.repository.query({ fromDate: from, toDate: to });
  }

  /**
   * Get the total count of logged notifications.
   */
  getCount(): number {
    return this.repository.count();
  }
}

