import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { Notification } from '../../src/models/notification.js';
import type { OrderCreatedEvent } from '../../src/events/event-types.js';

function makeNotification(overrides: Partial<Notification> = {}): Notification {
  return {
    id: 'notif-0001',
    recipient: 'alice@example.com',
    subject: 'Test Subject',
    body: 'Test body',
    type: 'order:confirmation',
    channel: 'email',
    sentAt: new Date('2026-01-15T10:00:00Z'),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('record', () => {
    it('should record a notification with sent status when no result provided', () => {
      const notification = makeNotification();
      const log = historyService.record(notification);

      expect(log.id).toBe('nlog-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.type).toBe('order:confirmation');
      expect(log.status).toBe('sent');
      expect(log.error).toBeUndefined();
    });

    it('should record a notification with delivered status on success', () => {
      const notification = makeNotification();
      const log = historyService.record(notification, {
        success: true,
        notificationId: 'notif-0001',
        channel: 'email',
      });

      expect(log.status).toBe('delivered');
      expect(log.error).toBeUndefined();
    });

    it('should record a notification with failed status on failure', () => {
      const notification = makeNotification();
      const log = historyService.record(notification, {
        success: false,
        notificationId: 'notif-0001',
        channel: 'email',
        error: 'SMTP timeout',
      });

      expect(log.status).toBe('failed');
      expect(log.error).toBe('SMTP timeout');
    });

    it('should generate sequential log IDs', () => {
      const n1 = makeNotification({ id: 'notif-0001' });
      const n2 = makeNotification({ id: 'notif-0002' });

      const log1 = historyService.record(n1);
      const log2 = historyService.record(n2);

      expect(log1.id).toBe('nlog-0001');
      expect(log2.id).toBe('nlog-0002');
    });

    it('should persist logs to the repository', () => {
      historyService.record(makeNotification());

      expect(historyService.getCount()).toBe(1);
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.record(
        makeNotification({
          id: 'notif-0001',
          recipient: 'alice@example.com',
          type: 'order:confirmation',
          channel: 'email',
          sentAt: new Date('2026-01-15T10:00:00Z'),
        }),
      );
      historyService.record(
        makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          type: 'order:status-update',
          channel: 'email',
          sentAt: new Date('2026-01-16T10:00:00Z'),
        }),
      );
      historyService.record(
        makeNotification({
          id: 'notif-0003',
          recipient: 'alice@example.com',
          type: 'order:status-update',
          channel: 'webhook',
          sentAt: new Date('2026-01-17T10:00:00Z'),
        }),
      );
    });

    it('should query by recipient', () => {
      const results = historyService.getByRecipient('alice@example.com');
      expect(results).toHaveLength(2);
      expect(results.every((r) => r.recipient === 'alice@example.com')).toBe(true);
    });

    it('should query by type', () => {
      const results = historyService.getByType('order:status-update');
      expect(results).toHaveLength(2);
    });

    it('should query by date range', () => {
      const results = historyService.getByDateRange(
        new Date('2026-01-16T00:00:00Z'),
        new Date('2026-01-17T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should query with multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        type: 'order:status-update',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should return empty array when no matches', () => {
      const results = historyService.getByRecipient('nobody@example.com');
      expect(results).toHaveLength(0);
    });

    it('should query by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('alice@example.com');
    });

    it('should query by status', () => {
      const results = historyService.query({ status: 'sent' });
      expect(results).toHaveLength(3);
    });
  });

  describe('updateStatus', () => {
    it('should update delivery status of a log entry', () => {
      const log = historyService.record(makeNotification());

      const updated = historyService.updateStatus(log.id, 'delivered');
      expect(updated.status).toBe('delivered');
    });

    it('should update status to failed with error', () => {
      const log = historyService.record(makeNotification());

      const updated = historyService.updateStatus(log.id, 'failed', 'Connection refused');
      expect(updated.status).toBe('failed');
      expect(updated.error).toBe('Connection refused');
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications sent through the notification service', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Allow async adapter dispatch to complete
      await new Promise((resolve) => setTimeout(resolve, 10));

      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.type).toBe('order:confirmation');
      expect(logs[0]?.status).toBe('delivered');
      expect(logs[0]?.subject).toContain('Order Confirmation');
    });

    it('should log notification as sent when no adapter is registered', async () => {
      const noAdapterService = new NotificationService(eventBus);
      const freshDb = new Database();
      const freshRepo = new NotificationLogRepository(freshDb);
      const freshHistory = new NotificationHistoryService(freshRepo);
      noAdapterService.setHistoryService(freshHistory);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const logs = freshHistory.query({});
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('sent');
    });
  });
});

